const input = $('regen_or_new').all().map(item => item.json);

const allDocuments = input.flatMap(req =>
  (req.documents || []).map(doc => ({
    ...doc,
    requestId: req.requestId
  }))
);

return allDocuments.map(doc => ({ json: doc }));

