// Функция генерации регистрационного номера
function generateRegNumber(documentType, counters) {
  const format = config.REG_NUMBER_FORMATS[documentType];
  if (!format) return { regNumber: "", counterUpdate: null };

  if (format.useParent) return { regNumber: "", counterUpdate: null };

  const counter = counters.find(c => 
    c.json[config.COLUMNS.COUNTERS.COUNTER_TYPE] === format.counter_name
  );

  let currentValue = counter ? 
    parseInt(counter.json[config.COLUMNS.COUNTERS.CURRENT_VALUE]) : 
    format.startFrom;

  currentValue += 1;

  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const year = String(now.getFullYear());
  const yy = year.slice(-2);

  let regNumber = format.format
    .replace("{number}", currentValue)
    .replace("{month}", month)
    .replace("{yy}", yy)
    .replace("{prefix}", format.prefix);

  return { 
    regNumber, 
    counterUpdate: { 
      name: format.counter_name, 
      value: currentValue 
    }
  };
}

// Готовим задачи
const tasks = [];
const counterUpdates = new Map();
const regNumbersByScenario = new Map();

const C = config.COLUMNS.REGISTRY;

registryRows.forEach((item, index) => {
  const reg = item.json;

  const rowNumber = index + 2;
  const id = reg[C.ID];
  const scenario = reg[C.SCENARIO];
  const fullName = reg[C.FULL_NAME] || "";
  const employee = reg[C.EMPLOYEE] || "не указан";
  const folderLink = reg[C.FOLDER]; // Ссылка на папку с документами

  // Проверяем обязательные поля
  if (!id) {
    console.log(`Пропускаем строку ${rowNumber} без ID`);
    // tasks.push({ 
    //   json: { 
    //     error: `❌ Строка ${rowNumber}: отсутствует ID`,
    //     rowNumber,
    //     action: "error"
    //   } 
    // });
    return;
  }

  if (!scenario) {
    console.log(`Пропускаем ID=${id}: нет сценария`);
    tasks.push({ 
      json: { 
        error: `❌ ID=${id}: отсутствует сценарий`,
        rowNumber,
        action: "error"
      } 
    });
    return;
  }

  // Получаем список документов для данного сценария
  const scenarioConfig = config.SCENARIOS[scenario];
  if (!scenarioConfig) {
    console.log(`Неизвестный сценарий: ${scenario}`);
    tasks.push({ 
      json: { 
        error: `❌ ID=${id}: неизвестный сценарий "${scenario}"`,
        rowNumber,
        action: "error"
      } 
    });
    return;
  }

  const documentsToGenerate = scenarioConfig.documents || [];
  console.log(`Обрабатываем ID=${id}, сценарий="${scenario}", документов: ${documentsToGenerate.length}`);

  // Определяем, существует ли папка с документами
  const hasExistingDocuments = folderLink && folderLink.trim() !== "";

  // Функция для создания задачи документа
  const createTask = (documentType, isUnderlayVersion = false) => {
    const templateKey = `${scenario}|${documentType}`;
    const template = templatesByDoc.get(templateKey);

    if (!template) {
      console.warn(`  ⚠️ Нет шаблона для: ${documentType} в сценарии ${scenario}`);
      tasks.push({ 
        json: { 
          error: `❌ ID=${id}: нет шаблона для документа "${documentType}" в сценарии "${scenario}"`,
          rowNumber,
          action: "error"
        } 
      });
      return;
    }

    const underlay = template[config.COLUMNS.TEMPLATES.UNDERLAY] === "Y";
    const folderType = underlay ? "С подложкой" : "Без подложки";

    let regNumber = "";
    const regVariable = template[config.COLUMNS.TEMPLATES.REG_VARIABLE];

    // Генерация регистрационного номера только для новых документов
    const isNewDocument = !hasExistingDocuments;

    console.log(`  Документ: ${documentType}`);
    console.log(`    - hasExistingDocuments: ${hasExistingDocuments}`);
    console.log(`    - isNewDocument: ${isNewDocument}`);

    if (regVariable && isNewDocument) {
      const format = config.REG_NUMBER_FORMATS[documentType];
      console.log(`    - format найден:`, !!format);

      if (format?.useParent) {
        console.log(`    - использует родительский номер`);
        const scenarioKey = `${id}_${scenario}`;
        regNumber = regNumbersByScenario.get(scenarioKey) || "";
        console.log(`    - найден родительский номер: "${regNumber}"`);

        if (!regNumber) {
          console.warn(`    - родительский номер не найден для ${scenarioKey}`);
        }
      } else if (format?.shared) {
        console.log(`    - shared номер для сценария ${scenario}`);
        const scenarioKey = `${id}_${scenario}`;
        if (!regNumbersByScenario.has(scenarioKey)) {
          const result = generateRegNumber(documentType, countersData);
          console.log(`    - сгенерирован shared номер: ${result.regNumber}`);
          regNumbersByScenario.set(scenarioKey, result.regNumber);
          if (result.counterUpdate) {
            counterUpdates.set(result.counterUpdate.name, result.counterUpdate.value);

            const counterToUpdate = countersData.find(c => 
              c.json[config.COLUMNS.COUNTERS.COUNTER_TYPE] === result.counterUpdate.name
            );
            if (counterToUpdate) {
              counterToUpdate.json[config.COLUMNS.COUNTERS.CURRENT_VALUE] = result.counterUpdate.value;
              console.log(`    - обновлен счетчик ${result.counterUpdate.name}: ${result.counterUpdate.value}`);
            }
          }
        }
        regNumber = regNumbersByScenario.get(scenarioKey);
      } else if (format) {
        const individualKey = `${id}_${scenario}_${documentType}_individual`;

        if (isUnderlayVersion) {
          // Подложка использует номер основного документа
          regNumber = regNumbersByScenario.get(individualKey) || "";
          console.log(`    - подложка использует номер основного документа: "${regNumber}"`);
        } else {
          // Основной документ генерирует новый номер
          console.log(`    - индивидуальный номер`);
          const result = generateRegNumber(documentType, countersData);
          console.log(`    - сгенерирован номер: ${result.regNumber}`);
          regNumber = result.regNumber;

          // Сохраняем номер для подложки
          regNumbersByScenario.set(individualKey, regNumber);

          if (result.counterUpdate) {
            counterUpdates.set(result.counterUpdate.name, result.counterUpdate.value);

            const counterToUpdate = countersData.find(c => 
              c.json[config.COLUMNS.COUNTERS.COUNTER_TYPE] === result.counterUpdate.name
            );
            if (counterToUpdate) {
              counterToUpdate.json[config.COLUMNS.COUNTERS.CURRENT_VALUE] = result.counterUpdate.value;
              console.log(`    - обновлен счетчик ${result.counterUpdate.name}: ${result.counterUpdate.value}`);
            }
          }
        }
      } else {
        console.log(`    - format не найден в REG_NUMBER_FORMATS`);
      }
    } else if (regVariable && !isNewDocument) {
      console.log(`    - документ существует, номер не генерируется`);
    } else {
      console.log(`    - regVariable пустая, номер не генерируется`);
    }

    const period = calculateStudyPeriod(reg);
    const fio = splitFIO(fullName);
    const fioDeclined = splitFIO(reg[C.FULL_NAME_DECLINED] || "");

    const variables = {
      "<<ID>>": id,
      "<<Фамилия>>": fio.surname,
      "<<Имя>>": fio.name,
      "<<Отчество>>": fio.patronymic,
      "<<Фамилия в склонении>>": fioDeclined.surname,
      "<<Имя в склонении>>": fioDeclined.name,
      "<<Отчество в склонении>>": fioDeclined.patronymic,
      "<<Программа>>": reg[C.PROGRAM] || "",
      "<<Квалификация>>": reg[C.QUALIFICATION] || "",
      "<<Специализация>>": reg[C.SPECIALIZATION] || "",
      "<<Часов>>": reg[C.HOURS] || "",
      "<<СНИЛС>>": reg[C.SNILS] || "",
      "<<Город>>": reg[C.CITY] || "Москва",
      "<<Компания>>": reg[C.COMPANY] || "-",
      "<<Документ об образовании>>": reg[C.EDUCATION_DOC] || "",
      "<<Дата>>": period.dateFull,
      "<<Окончание обучения>>": period.shortEnd,
      "<<от>>": period.startDay,
      "<<м-от>>": period.startMonth,
      "<<г-от>>": period.startYear,
      "<<до>>": period.endDay,
      "<<м-до>>": period.endMonth,
      "<<г-до>>": period.endYear,
      "<<г-о>>": period.startYearShort,
      "<<г-д>>": period.endYearShort
    };

    // Добавляем переменную родительского документа, если нужно
    const format = config.REG_NUMBER_FORMATS[documentType];
    if (format?.parentVariable) {
      const scenarioKey = `${id}_${scenario}`;
      const mainDocRegNumber = regNumbersByScenario.get(scenarioKey);

      if (mainDocRegNumber) {
        variables[`<<${format.parentVariable}>>`] = mainDocRegNumber;
        console.log(`    - добавлена переменная родительского документа: <<${format.parentVariable}>> = ${mainDocRegNumber}`);
      } else {
        console.warn(`    - родительский номер не найден для переменной <<${format.parentVariable}>>`);
      }
    }

    // Добавляем регистрационный номер в переменные
    if (regVariable && regNumber) {
      variables[`<<${regVariable}>>`] = regNumber;
    }

    // Определяем существующий документ
    const existingDocument = hasExistingDocuments ? folderLink : null;

    // Формируем имя файла
    const firstName = fullName.split(' ')[0];
    const targetName = `${id}_${firstName}_${documentType}`;

    tasks.push({
      json: {
        id,
        rowNumber,
        employee,
        scenario,
        documentType,
        templateId: template[config.COLUMNS.TEMPLATES.TEMPLATE_LINK],
        templateType: template[config.COLUMNS.TEMPLATES.TYPE],
        folderType,
        underlay,
        variables,
        regNumber,
        targetName,
        existingDocument,
        action: existingDocument ? "update_document" : "create_document"
      }
    });
  };

  // Генерируем документы согласно сценарию
  documentsToGenerate.forEach(documentType => {
    // Создаем основной документ
    createTask(documentType, false);

    // Проверяем наличие версии с подложкой
    const underlayDocumentType = `${documentType} (подложка)`;
    const underlayTemplateKey = `${scenario}|${underlayDocumentType}`;
    const underlayTemplate = templatesByDoc.get(underlayTemplateKey);

    if (underlayTemplate) {
      console.log(`  Найден шаблон с подложкой: ${underlayDocumentType}`);
      createTask(underlayDocumentType, true);
    }
  });
});

// Добавляем задачу обновления счетчиков
if (counterUpdates.size > 0) {
  tasks.push({
    json: {
      action: "update_counters",
      counters: Array.from(counterUpdates.entries()).map(([name, value]) => ({
        name,
        value
      }))
    }
  });
}

console.log(`\n=== ИТОГО ===`);
console.log(`Подготовлено задач: ${tasks.length}`);
console.log(`- Создать документов: ${tasks.filter(t => t.json.action === "create_document").length}`);
console.log(`- Обновить документов: ${tasks.filter(t => t.json.action === "update_document").length}`);
console.log(`- Ошибок: ${tasks.filter(t => t.json.action === "error").length}`);
console.log(`- Обновить счетчиков: ${counterUpdates.size}`);

// ===============================================
//     ГРУППИРОВКА ПО ЗАЯВКАМ
// ===============================================

// Отделяем служебные задачи
const serviceTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "update_counters" || data.action === "error";
});

// Получаем только задачи создания/обновления документов
const documentTasks = tasks.filter(task => {
  const data = task.json;
  return data.action === "create_document" || data.action === "update_document";
});

console.log(`\nГруппировка: ${documentTasks.length} документов, ${serviceTasks.length} служебных`);

// Группируем по ID заявки
const requestGroups = new Map();

documentTasks.forEach(task => {
  const data = task.json;
  const requestId = data.id;

  if (!requestGroups.has(requestId)) {
    requestGroups.set(requestId, {
      id: requestId,
      employee: data.employee,
      scenario: data.scenario,
      fullName: `${data.variables["<<Фамилия>>"]} ${data.variables["<<Имя>>"]} ${data.variables["<<Отчество>>"]}`,
      regNumber: data.regNumber,
      documents: [],
      totalDocuments: 0,
      createdCount: 0,
      updatedCount: 0
    });
  }

  const group = requestGroups.get(requestId);

  // Добавляем документ в группу
  group.documents.push({
    rowNumber: data.rowNumber,
    documentType: data.documentType,
    templateId: data.templateId,
    templateType: data.templateType,
    folderType: data.folderType,
    underlay: data.underlay,
    variables: data.variables,
    targetName: data.targetName,
    existingDocument: data.existingDocument,
    action: data.action
  });

  // Увеличиваем счетчики
  group.totalDocuments++;
  if (data.action === "create_document") {
    group.createdCount++;
  } else if (data.action === "update_document") {
    group.updatedCount++;
  }
});

// Преобразуем группы в массив пакетов
const requestPackets = Array.from(requestGroups.values()).map(group => ({
  json: {
    requestId: group.id,
    employee: group.employee,
    scenario: group.scenario,
    fullName: group.fullName,
    regNumber: group.regNumber,

    // Статистика пакета
    summary: {
      totalDocuments: group.totalDocuments,
      toCreate: group.createdCount,
      toUpdate: group.updatedCount
    },

    // Список документов для генерации
    documents: group.documents,

    // Метаданные
    processingType: "batch",
    createdAt: new Date().toISOString()
  }
}));

// Объединяем пакеты и служебные задачи
const result = [...requestPackets, ...serviceTasks];

console.log(`\n=== РЕЗУЛЬТАТ ГРУППИРОВКИ ===`);
console.log(`Пакетов заявок: ${requestPackets.length}`);
requestPackets.forEach(packet => {
  const data = packet.json;
  console.log(`  ${data.requestId}: ${data.summary.totalDocuments} документов (создать: ${data.summary.toCreate}, обновить: ${data.summary.toUpdate})`);
});

return result;

// Получаем входные данные
const items = $input.all();
const results = [];

// Обрабатываем каждый элемент
for (const item of items) {
  const data = item.json;

  // Проверяем, что это объект заявки (не action)
  if (data.requestId && data.documents) {
    const regNumbers = new Set(); // Используем Set для уникальных значений

    // Проходим по всем документам в заявке
    for (const doc of data.documents) {
      if (doc.variables) {
        // Извлекаем все переменные, содержащие "Рег" в названии
        for (const [key, value] of Object.entries(doc.variables)) {
          if (key.includes('Рег')) {
            // Удаляем << >> из названия переменной и формируем строку
            const cleanKey = key.replace(/<<|>>/g, '');
            regNumbers.add(`${cleanKey}:${value}`);
          }
        }
      }
    }

    // Добавляем результат для этой заявки
    results.push({
      requestId: data.requestId,
      regNumbers: Array.from(regNumbers)
    });
  }
}

return results.map(item => ({ json: item }));

const input = $('regen_or_new').all().map(item => item.json);

const allDocuments = input.flatMap(req =>
  (req.documents || []).map(doc => ({
    ...doc,
    requestId: req.requestId
  }))
);

return allDocuments.map(doc => ({ json: doc }));

