// Получаем данные из предыдущей ноды
const foldersData = $('CreateStudentFolder').all();
// Создаем один объект со всеми REQ-номерами
const result = {};

foldersData.forEach(item => {
  const data = item.json;

  result[data.name.split('_')[2]] = {
    id: data.id
  };
});

return [result];

// Входные данные из предыдущего нода
const input = $("GetFolderFiles").first().json;

// Извлекаем массив файлов
const files = input.files;

// Превращаем каждый файл в отдельный item
return files.map(file => ({ json: file }));

